mapper.select:
SELECT e.*, p.paper_name AS paper_name
FROM exam e
LEFT JOIN paper p ON e.paper_id = p.id

    AND e.creator_id = #{creatorId}
    AND e.publish_status = #{publishStatus}
    AND e.exam_name LIKE CONCAT('%', #{keyword}, '%')

ORDER BY e.id DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(1) FROM exam

    AND creator_id = #{creatorId}
    AND publish_status = #{publishStatus}
    AND exam_name LIKE CONCAT('%', #{keyword}, '%')

SELECT DISTINCT e.* FROM exam e
JOIN exam_paper ep ON e.id = ep.exam_id
WHERE e.publish_status = 1
AND ep.student_id = #{studentId}
AND e.start_time <= #{now} AND e.end_time >= #{now}
